import React, { useEffect, useState, useCallback } from 'react';
import api from '../utils/api';
import { useAuth } from '../hooks/useAuth';
import Toast from '../components/Toast';

const COLORS = ['#6366f1','#10b981','#3b82f6','#f59e0b','#ec4899','#8b5cf6','#14b8a6','#ef4444','#f97316','#06b6d4'];
const inp: React.CSSProperties = { width:'100%', padding:'9px 12px', border:'2px solid #e8e0d0', borderRadius:9, fontSize:13, fontFamily:'inherit', outline:'none', color:'#1a1a2e' };
const lbl: React.CSSProperties = { display:'block', fontSize:12, fontWeight:600, color:'#6b7280', marginBottom:6 };

export default function Categories() {
  const { user } = useAuth();
  const isStaff = user?.userType === 'user';
  const isLibrarian = user?.role === 'librarian';
  const [categories, setCategories] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(false);
  const [editing, setEditing] = useState<any>(null);
  const [form, setForm] = useState({ name: '', description: '', color: '#6366f1' });
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [toast, setToast] = useState<{ message: string; type: 'success'|'error'|'info'|'warning' } | null>(null);

  const load = useCallback(() => {
    api.get('/categories').then(r => { setCategories(r.data.data || []); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  useEffect(() => { load(); }, [load]);

  const openAdd = () => { setEditing(null); setForm({ name:'', description:'', color:'#6366f1' }); setError(''); setModal(true); };
  const openEdit = (cat: any) => { setEditing(cat); setForm({ name: cat.name, description: cat.description || '', color: cat.color }); setError(''); setModal(true); };

  const save = async () => {
    if (!form.name.trim()) { setError('Category name is required!'); return; }
    setSaving(true); setError('');
    try {
      if (editing) {
        await api.put(`/categories/${editing.id}`, form);
        setToast({ message: `"${form.name}" updated successfully`, type: 'success' });
      } else {
        await api.post('/categories', form);
        setToast({ message: `"${form.name}" category created!`, type: 'success' });
      }
      setModal(false); load();
    } catch (e: any) {
      setError(e.response?.data?.message || 'Error saving category');
    } finally { setSaving(false); }
  };

  const deleteCategory = async (cat: any) => {
    if (cat.book_count > 0) { setToast({ message: `Cannot delete "${cat.name}" — it has ${cat.book_count} books!`, type: 'warning' }); return; }
    if (!window.confirm(`Delete category "${cat.name}"?`)) return;
    try {
      await api.delete(`/categories/${cat.id}`);
      setToast({ message: `"${cat.name}" deleted`, type: 'success' });
      load();
    } catch { setToast({ message: 'Failed to delete', type: 'error' }); }
  };

  return (
    <div className="page-enter" style={{ padding: 32 }}>
      {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:24 }}>
        <div>
          <h1 style={{ fontFamily:"'Playfair Display',serif", fontSize:28, fontWeight:700 }}>Categories</h1>
          <p style={{ color:'#9ca3af', fontSize:13, marginTop:4 }}>{categories.length} categories</p>
        </div>
        {isStaff && (
          <button onClick={openAdd}
            style={{ padding:'9px 20px', background:'#1a1a2e', color:'#fff', border:'none', borderRadius:10, fontSize:13, fontWeight:600, cursor:'pointer', fontFamily:'inherit' }}>
            + Add Category
          </button>
        )}
      </div>

      {loading ? <div style={{ textAlign:'center', padding:80, color:'#9ca3af' }}>Loading...</div> : (
        <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:16 }}>
          {categories.length ? categories.map(cat => (
            <div key={cat.id} style={{ background:'#fff', border:'1px solid #e8e0d0', borderRadius:16, padding:22 }}>
              <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:14 }}>
                <div style={{ width:48, height:48, borderRadius:12, background:cat.color+'20', display:'flex', alignItems:'center', justifyContent:'center', fontSize:22 }}>📂</div>
                {isStaff && (
                  <div style={{ display:'flex', gap:4 }}>
                    <button onClick={() => openEdit(cat)}
                      style={{ padding:'5px 9px', background:'#f5f0e8', border:'none', borderRadius:7, fontSize:12, cursor:'pointer' }}>✏️</button>
                    {isLibrarian && (
                      <button onClick={() => deleteCategory(cat)}
                        style={{ padding:'5px 9px', background:'#fee2e2', border:'none', borderRadius:7, fontSize:12, cursor:'pointer' }}>🗑️</button>
                    )}
                  </div>
                )}
              </div>
              <h3 style={{ fontFamily:"'Playfair Display',serif", fontSize:17, fontWeight:700, marginBottom:6 }}>{cat.name}</h3>
              <p style={{ fontSize:12, color:'#9ca3af', marginBottom:14, lineHeight:1.5, minHeight:36 }}>{cat.description || 'No description'}</p>
              <div style={{ borderTop:'1px solid #e8e0d0', paddingTop:12, display:'flex', justifyContent:'space-between', alignItems:'center' }}>
                <div>
                  <span style={{ fontFamily:"'Playfair Display',serif", fontSize:22, fontWeight:700, color:cat.color }}>{cat.book_count}</span>
                  <span style={{ fontSize:12, color:'#9ca3af', marginLeft:4 }}>books</span>
                </div>
                <div style={{ width:12, height:12, borderRadius:'50%', background:cat.color }} />
              </div>
            </div>
          )) : (
            <div style={{ gridColumn:'1/-1', textAlign:'center', padding:80, color:'#9ca3af' }}>
              <div style={{ fontSize:48, marginBottom:12 }}>📂</div>
              <p style={{ fontSize:15, fontWeight:600 }}>No categories yet</p>
              {isStaff && <p style={{ fontSize:13, marginTop:6 }}>Click "+ Add Category" to create one</p>}
            </div>
          )}
        </div>
      )}

      {/* Add/Edit Modal */}
      {modal && (
        <div style={{ position:'fixed', inset:0, background:'rgba(26,26,46,0.5)', backdropFilter:'blur(4px)', zIndex:1000, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>
          <div style={{ background:'#fff', borderRadius:20, padding:28, width:'100%', maxWidth:440 }}>
            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:22 }}>
              <h2 style={{ fontFamily:"'Playfair Display',serif", fontSize:20, fontWeight:700 }}>{editing ? 'Edit Category' : 'Add Category'}</h2>
              <button onClick={() => setModal(false)} style={{ background:'#f5f0e8', border:'none', width:32, height:32, borderRadius:8, cursor:'pointer', fontSize:16 }}>✕</button>
            </div>
            {error && <div style={{ background:'#fee2e2', color:'#dc2626', padding:'10px 14px', borderRadius:9, fontSize:13, marginBottom:14 }}>{error}</div>}

            <div style={{ marginBottom:16 }}>
              <label style={lbl}>Category Name *</label>
              <input style={inp} value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} placeholder="e.g. Science & Technology" />
            </div>

            <div style={{ marginBottom:16 }}>
              <label style={lbl}>Description</label>
              <textarea style={{ ...inp, minHeight:70, resize:'vertical' }} value={form.description} onChange={e => setForm(f => ({ ...f, description: e.target.value }))} placeholder="Brief description..." />
            </div>

            <div style={{ marginBottom:22 }}>
              <label style={lbl}>Color</label>
              <div style={{ display:'flex', gap:8, flexWrap:'wrap' }}>
                {COLORS.map(c => (
                  <button key={c} onClick={() => setForm(f => ({ ...f, color: c }))}
                    style={{ width:32, height:32, borderRadius:8, background:c, border: form.color === c ? '3px solid #1a1a2e' : '3px solid transparent', cursor:'pointer', transition:'all .15s' }} />
                ))}
              </div>
              <div style={{ marginTop:10, display:'flex', alignItems:'center', gap:10 }}>
                <div style={{ width:36, height:36, borderRadius:9, background:form.color+'20', display:'flex', alignItems:'center', justifyContent:'center', fontSize:18 }}>📂</div>
                <span style={{ fontSize:13, color:'#6b7280' }}>Preview — {form.name || 'Category Name'}</span>
              </div>
            </div>

            <div style={{ display:'flex', gap:10 }}>
              <button onClick={() => setModal(false)} style={{ flex:1, padding:10, background:'#f5f0e8', border:'none', borderRadius:10, cursor:'pointer', fontFamily:'inherit', fontSize:13 }}>Cancel</button>
              <button onClick={save} disabled={saving} style={{ flex:2, padding:10, background:'#1a1a2e', color:'#fff', border:'none', borderRadius:10, cursor:'pointer', fontFamily:'inherit', fontSize:13, fontWeight:600 }}>
                {saving ? 'Saving...' : editing ? 'Update Category' : '+ Create Category'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
